import{_ as a,o as t,c as i,a0 as s}from"./chunks/framework.jwovEGr5.js";const o="data:image/png;base64,iVBORw0KGgoAAAANSUhEUgAAAAEAAAABCAYAAAAfFcSJAAAADUlEQVR4nGMAAQAABQABDQottAAAAABJRU5ErkJggg==",m=JSON.parse('{"title":"Icons (and Badges)","description":"","frontmatter":{},"headers":[],"relativePath":"admin/icons-and-badges.md","filePath":"admin/icons-and-badges.md"}'),r={name:"admin/icons-and-badges.md"};function l(n,e,c,d,h,u){return t(),i("div",null,[...e[0]||(e[0]=[s('<h1 id="icons-and-badges" tabindex="-1">Icons (and Badges) <a class="header-anchor" href="#icons-and-badges" aria-label="Permalink to &quot;Icons (and Badges)&quot;">​</a></h1><p>This guide is for <code>Supreme Admin</code> users only.</p><p>The current admin UI has a real <strong>Icons</strong> library, but the <strong>Badges</strong> page is only a preview area right now, not a full badge-management screen.</p><p><img src="'+o+'" alt="Icons admin"></p><h2 id="what-currently-works" tabindex="-1">What currently works <a class="header-anchor" href="#what-currently-works" aria-label="Permalink to &quot;What currently works&quot;">​</a></h2><p>The <strong>Icons</strong> page is usable today.</p><p>You can:</p><ul><li>browse the shared icon library</li><li>search icons</li><li>filter by category</li><li>copy an icon key for reuse elsewhere</li><li>create a custom icon</li><li>edit a custom icon</li><li>delete a custom icon</li></ul><h2 id="system-icons-vs-custom-icons" tabindex="-1">System icons vs custom icons <a class="header-anchor" href="#system-icons-vs-custom-icons" aria-label="Permalink to &quot;System icons vs custom icons&quot;">​</a></h2><p>There are two icon types in practice:</p><ul><li>built-in system icons</li><li>custom icons you add yourself</li></ul><p>System icons are locked:</p><ul><li>they can be reviewed</li><li>their keys are reserved</li><li>they cannot be deleted</li></ul><p>If you want a variation, create a custom alternative instead.</p><h2 id="creating-a-custom-icon" tabindex="-1">Creating a custom icon <a class="header-anchor" href="#creating-a-custom-icon" aria-label="Permalink to &quot;Creating a custom icon&quot;">​</a></h2><p>The create and edit form lets you set:</p><ul><li>key</li><li>label</li><li>category</li><li>type</li><li>value</li><li>color</li></ul><p>Supported icon types are:</p><ul><li><code>emoji</code></li><li><code>svg</code></li><li><code>image_url</code></li></ul><p>The page also shows a live preview before you save.</p><h2 id="safety-checks" tabindex="-1">Safety checks <a class="header-anchor" href="#safety-checks" aria-label="Permalink to &quot;Safety checks&quot;">​</a></h2><p>The icon system validates custom values.</p><p>For example:</p><ul><li>image URLs must be real <code>http</code> or <code>https</code> URLs</li><li>unsafe SVG content is rejected</li></ul><p>That helps keep the shared icon registry safe to reuse across the app.</p><h2 id="where-icons-are-used" tabindex="-1">Where icons are used <a class="header-anchor" href="#where-icons-are-used" aria-label="Permalink to &quot;Where icons are used&quot;">​</a></h2><p>This shared icon library feeds places such as:</p><ul><li>roles</li><li>events</li><li>rewards</li><li>player attributes and status displays</li></ul><h2 id="what-i-found-about-the-badges-page" tabindex="-1">What I found about the badges page <a class="header-anchor" href="#what-i-found-about-the-badges-page" aria-label="Permalink to &quot;What I found about the badges page&quot;">​</a></h2><p>The current <strong>Badges</strong> admin route is only a small preview page showing sample badges and attribute chips. It does <strong>not</strong> currently provide badge CRUD or a real badge-management workflow.</p><p>So, today:</p><ul><li>icon management is live</li><li>badge management is not yet available as a real admin interface</li></ul><p>If you need badge-like changes today, look at the settings and status systems that already exist elsewhere in the app rather than expecting a dedicated badge editor here.</p><h2 id="related" tabindex="-1">Related <a class="header-anchor" href="#related" aria-label="Permalink to &quot;Related&quot;">​</a></h2><ul><li><a href="./manage-roles.html">Create &amp; Edit Custom Roles</a></li><li><a href="./../reference/permission-catalog.html">Permission Reference</a></li></ul>',35)])])}const g=a(r,[["render",l]]);export{m as __pageData,g as default};
